nta.declaration:
// Priority Ceiling Protocol (PCP) - Resource Access Protocols
// Author: Daniel Chidi Chimezie, Matriculation Number: 1230515
// Submission-ready UPPAAL model

const int NTASKS = 3;
const int NRES = 2;
const int FREE = -1;

// Higher number means higher priority.
const int LOW = 1;
const int MEDIUM = 2;
const int HIGH = 3;

// Resource identifiers.
const int R1 = 0;
const int R2 = 1;

// Resource ceilings:
// R1 is shared by T1 and T3, therefore ceiling(R1) = HIGH.
// R2 is used by T2, therefore ceiling(R2) = MEDIUM.
const int resCeil[NRES] = {HIGH, MEDIUM};

bool locked[NRES] = {false, false};
int owner[NRES] = {FREE, FREE};

int systemCeilingExcluding(int tid)
{
    int c = 0;
    int r;
    for (r = 0; r < NRES; r++) {
        if (locked[r] && owner[r] != tid && resCeil[r] > c) {
            c = resCeil[r];
        }
    }
    return c;
}

bool canEnter(int tid, int prio, int rid)
{
    return !locked[rid] && prio > systemCeilingExcluding(tid);
}

void lockResource(int tid, int rid)
{
    locked[rid] = true;
    owner[rid] = tid;
}

void unlockResource(int tid, int rid)
{
    if (owner[rid] == tid) {
        locked[rid] = false;
        owner[rid] = FREE;
    }
}

nta.system:
// Process instances
// T1: highest-priority task uses R1.
// T2: medium-priority task uses R2.
// T3: lowest-priority task uses R1.
T1 = Task(1, HIGH, R1);
T2 = Task(2, MEDIUM, R2);
T3 = Task(3, LOW, R1);

system T1, T2, T3;
